const raw = items[0].json;
let jobs = [];
try {
  const decoded = Buffer.from(raw.content, 'base64').toString('utf8');
  jobs = JSON.parse(decoded);
  if (!Array.isArray(jobs)) jobs = [];
} catch (e) {
  jobs = [];
}

jobs.sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0));
const top5 = jobs.slice(0, 5);

return top5.map(j => ({ json: j }));

const job = items[0].json;

const prompt = `Extract the top 15 ATS keywords from this job posting for a resume tailoring exercise.\nJob Title: ${job.title}\nCompany: ${job.company}\nSource: ${job.source}\nDescription: ${job.description || 'No description provided — infer from title and company.'}\n\nReturn ONLY a JSON object with one field: keywords (array of 15 strings). No other text.`;

return [{
  json: {
    _pt: job,
    groq_request: {
      model: 'openai/gpt-oss-120b',
      messages: [
        { role: 'system', content: 'You are an expert ATS keyword extractor. Return only valid JSON.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.1,
      max_tokens: 512
    }
  }
}];

const groqResp = items[0].json;
const ptData = $('Build Keyword Request').first().json._pt;

let keywords = [];
try {
  const content = groqResp.choices[0].message.content;
  const jsonMatch = content.match(/\{.*\}/s);
  const parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
  keywords = parsed.keywords || [];
} catch (e) {
  keywords = [];
}

const candidateProfile = `[CANDIDATE NAME]\nEmail: [CANDIDATE_EMAIL@EXAMPLE.COM] | Phone: [PHONE NUMBER]\nGitHub: github.com/[GITHUB_USERNAME] | Location: Guntur, Andhra Pradesh\nB.Tech AI & Machine Learning, VVIT Guntur, CGPA 8.35, Graduating Sep 2026\n\nProjects:\n1. EMERALD — ~10M param GPT-style decoder-only transformer, PyTorch, custom BPE tokenizer, Wikipedia training, Flask inference server, live at abhinay7.netlify.app\n2. Fake News Detection — TensorFlow + NLTK/SpaCy, TF-IDF + semantic features, Flask REST API\n3. AI Crop Prediction — Scikit-learn (22 crops), FastAPI backend, Flutter mobile app\n4. Binance Trading Bot — Typer CLI, httpx, HMAC-SHA256\n\nSkills: Python, PyTorch, TensorFlow, Scikit-learn, Flask, FastAPI, NLTK, SpaCy, Pandas, NumPy, Flutter, Dart, JavaScript, n8n\nCertifications: NPTEL Elite — Introduction to Large Language Models\nLeadership: ACM Membership Chair VVIT | SIH 2025 Internal Selection`;

const prompt = `Generate a highly professional, tailored resume for the following job. Incorporate the provided keywords naturally into bullet points.\n\nCRITICAL RESUME RULES:\n1. Use the Harvard Business School resume format: Action Verb + Task + Quantifiable Result.\n2. NO fluff, NO clichés (do not use vague words like "passionate", "innovative", "hard-working").\n3. Output the resume in pure Markdown format (.md). Use # for headers, ** for bolding key tech/metrics, and bullet points for experiences.\n4. Keep the tone strictly professional, objective, and impact-driven.\n\nJob Title: ${ptData.title}\nCompany: ${ptData.company}\nATS Keywords to incorporate: ${keywords.join(', ')}\n\nCandidate Profile:\n${candidateProfile}\n\nOutput ONLY the Markdown resume, no conversational text.`;

return [{
  json: {
    _pt: ptData,
    keywords,
    groq_request: {
      model: 'openai/gpt-oss-120b',
      messages: [
        { role: 'system', content: 'You are an expert resume writer who creates ATS-optimized, Harvard-style resumes. Output strictly in Markdown format.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.3,
      max_tokens: 2048
    }
  }
}];

const groqResp = items[0].json;
const ptData = $('Parse KW — Build Resume Req').first().json._pt;
const keywords = $('Parse KW — Build Resume Req').first().json.keywords;

let resumeText = '';
try {
  resumeText = groqResp.choices[0].message.content || '';
} catch (e) {
  resumeText = '';
}

const prompt = `You are an ATS scoring expert. Score how well the following resume matches the target job.\n\nJob Title: ${ptData.title}\nCompany: ${ptData.company}\nRequired Keywords: ${keywords.join(', ')}\n\nResume:\n${resumeText.slice(0, 3000)}\n\nReturn ONLY a JSON object with these fields:\n- overall_score: integer 0-100\n- keyword_match_rate: float 0-1\n- matched_keywords: array of matched keyword strings\n- missing_keywords: array of missing keyword strings\n- strengths: array of 3 strength strings\n- improvements: array of 3 improvement strings\n\nReturn only the JSON, no other text.`;

return [{
  json: {
    _pt: ptData,
    resume_text: resumeText,
    groq_request: {
      model: 'openai/gpt-oss-120b',
      messages: [
        { role: 'system', content: 'You are an expert ATS resume scorer. Return only valid JSON.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.1,
      max_tokens: 1024
    }
  }
}];

const groqResp = items[0].json;
const ptData = $('Parse Resume — Build ATS Req').first().json._pt;
const resumeText = $('Parse Resume — Build ATS Req').first().json.resume_text;

let atsReport = {};
try {
  const content = groqResp.choices[0].message.content;
  const jsonMatch = content.match(/\{.*\}/s);
  atsReport = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  atsReport = { overall_score: 0, error: 'parse_failed' };
}

atsReport.job_id = ptData.job_id;
atsReport.job_title = ptData.title;
atsReport.company = ptData.company;
atsReport.scored_at = new Date().toISOString();

const resumeB64 = Buffer.from(resumeText).toString('base64');
const atsB64 = Buffer.from(JSON.stringify(atsReport, null, 2)).toString('base64');

return [{
  json: {
    job_id: ptData.job_id,
    job_title: ptData.title,
    company: ptData.company,
    resume_text: resumeText,
    resume_b64: resumeB64,
    ats_report: atsReport,
    ats_b64: atsB64
  }
}];

const pkg = items[0].json;
return [{
  json: {
    github_payload: {
      message: `Add resume for ${pkg.job_id}`,
      content: pkg.resume_b64,
      branch: 'state'
    },
    job_id: pkg.job_id,
    ats_report: pkg.ats_report,
    ats_b64: pkg.ats_b64
  }
}];

const pkg = items[0].json;
return [{
  json: {
    github_payload: {
      message: `Add ATS report for ${pkg.job_id}`,
      content: pkg.ats_b64,
      branch: 'state'
    },
    job_id: pkg.job_id
  }
}];
